# --- GraphQL Schema ---
type_defs = """
    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String
        author: User!
    }

    type Query {
        user(id: ID!): User
        users: [User!]!
        post(id: ID!): Post
        posts: [Post!]!
    }
"""

# --- Resolvers ---
query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")

@query.field("user")
def resolve_user(_, info, id):
    return users_db.get(id)

@query.field("users")
def resolve_users(_, info):
    return list(users_db.values())

@query.field("post")
def resolve_post(_, info, id):
    return posts_db.get(id)

@query.field("posts")
def resolve_posts(_, info):
    return list(posts_db.values())

@user_type.field("posts")
def resolve_user_posts(user, info):
    return [post for post in posts_db.values() if post["author_id"] == user["id"]]

@post_type.field("author")
def resolve_post_author(post, info):
    return users_db.get(post["author_id"])


# --- Custom Context Class ---
class UserContext:
    def __init__(self, current_user_id=None):
        self.current_user_id = current_user_id
        self.current_user = users_db.get(current_user_id) if current_user_id else None

def get_context_value(request):
    auth_header = request.headers.get("Authorization")
    current_user_id = None
    if auth_header and auth_header.startswith("Bearer "):
        # In a real app, this would validate a JWT and extract user ID
        # For simplicity, we'll just use the ID directly for now
        current_user_id = auth_header.split(" ")[1]
    return UserContext(current_user_id)

# --- GraphQL Schema and Application Setup ---
schema = make_executable_schema(type_defs, [query, user_type, post_type])
app = Flask(__name__)

@app.route("/graphql", methods=["POST"])
def graphql_server():
    request_data = request.get_json()
    success, result = graphql_sync(
        schema,
        request_data,
        context_value=get_context_value(request),
        debug=app.debug,
    )
    status_code = 200 if success else 400
    return jsonify(result), status_code

if __name__ == "__main__":
    app.run(debug=True)